import { api } from "encore.dev/api";
import { createYoga, createSchema } from "graphql-yoga";

const schema = createSchema({
  typeDefs: `
    type Query {
      hello(name: String): String!
    }
  `,
  resolvers: {
    Query: {
      hello: (_, { name }: { name?: string }) => `Hello, ${name || "World"}!`,
    },
  },
});

const yoga = createYoga({
  schema,
  graphqlEndpoint: "/graphql",
  // Disable landing page to keep it simple and avoid issues with raw responses
  landingPage: false,
});

export const graphql = api.raw(
  { expose: true, path: "/graphql", method: "POST" },
  async (req) => {
    const { method, url, headers, body } = req;

    // Construct a full URL for Yoga
    const fullUrl = new URL(url, "http://localhost");

    const response = await yoga.fetch(fullUrl.toString(), {
      method,
      headers: headers as Record<string, string>,
      body,
    });

    const respHeaders: Record<string, string> = {};
    response.headers.forEach((value, key) => {
      respHeaders[key] = value;
    });

    return {
      statusCode: response.status,
      headers: respHeaders,
      body: new Uint8Array(await response.arrayBuffer()),
    };
  }
);

