import { api } from "encore.dev/api";
import { graphql as executeGraphQL, buildSchema } from "graphql";

const schema = buildSchema(`
  type Query {
    hello(name: String): String!
  }
`);

const rootValue = {
  hello: ({ name }: { name?: string }) => `Hello, ${name || "World"}!`,
};

export const graphql = api.raw(
  { expose: true, path: "/graphql", method: "POST" },
  async (req) => {
    const body = req.body;
    let finalBody: Uint8Array;
    if (body instanceof Uint8Array) {
      finalBody = body;
    } else {
      finalBody = await body.readAll();
    }

    const bodyText = new TextDecoder().decode(finalBody);
    const { query, variables } = JSON.parse(bodyText);

    const result = await executeGraphQL({
      schema,
      source: query,
      variableValues: variables,
      rootValue,
    });

    return {
      statusCode: 200,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(result),
    };
  }
);

