export const graphql = api.raw(
  { expose: true, path: "/graphql", method: "POST" },
  async (req) => {
    const body = req.body;
    let chunks: Uint8Array[] = [];

    // @ts-ignore
    while (true) {
      const chunk = await body.read();
      if (chunk === null || chunk === undefined) break;
      chunks.push(chunk);
    }

    const totalLength = chunks.reduce((acc, chunk) => acc + chunk.length, 0);
    const finalBody = new Uint8Array(totalLength);
    let offset = 0;
    for (const chunk of chunks) {
      finalBody.set(chunk, offset);
      offset += chunk.length;
    }

    const bodyText = new TextDecoder().decode(finalBody);
    const { query, variables } = JSON.parse(bodyText);

    const result = await executeGraphQL({
      schema,
      source: query,
      variableValues: variables,
      rootValue,
    });

    return {
      statusCode: 200,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(result),
    };
  }
);

