import { api } from "encore.dev/api";
import { graphql as executeGraphQL, buildSchema } from "graphql";

const schema = buildSchema(`
  type Query {
    hello(name: String): String!
  }
`);

const rootValue = {
  hello: ({ name }: { name?: string }) => `Hello, ${name || "World"}!`,
};

interface GraphQLRequest {
  query: string;
  variables?: Record<string, any>;
}

interface GraphQLResponse {
  data?: any;
  errors?: any[];
}

// Using api instead of api.raw because of body reading issues in local environment.
// But we will try api.raw again for the final deployment if needed.
export const graphql = api(
  { expose: true, path: "/graphql", method: "POST" },
  async (params: GraphQLRequest): Promise<GraphQLResponse> => {
    const result = await executeGraphQL({
      schema,
      source: params.query,
      variableValues: params.variables,
      rootValue,
    });
    return result as GraphQLResponse;
  }
);

